template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer, size_t bytes_to_peek) {
    // Get the actual number of bytes available in the buffer
    size_t available = buffer.size();

    // Only peek up to the number of bytes actually available
    size_t bytes_to_copy = std::min(bytes_to_peek, available);

    // Create result vector with appropriate size
    std::vector<uint8_t> result(bytes_to_copy);

    // Peek the data without advancing the read pointer
    if (bytes_to_copy > 0) {
        buffer.peek(result.data(), bytes_to_copy);
    }

    return result;
}

