    // Get the amount of readable data available
    size_t available = storage.readable();

    // Don't preview more than what's available
    size_t to_preview = std::min(bytes_to_preview, available);

    // Create result vector with the appropriate size
    std::vector<uint8_t> result(to_preview);

    // Peek at the data without consuming it (without advancing read pointer)
    if (to_preview > 0) {
        storage.peek(result.data(), to_preview);
    }

    return result;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;

    // Get the number of bytes available to read
    status.readable_size = storage.readable();

    // Get the number of bytes available to write (free space)
    status.free_space = storage.writable();

    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Reset both read and write offsets to their initial state
    storage.reset();
}

