#include <hexi/shared.h>
#include <cstring>
#include <cstddef>

using namespace hexi::detail;

bool check_regions_overlap(const void* src, std::size_t src_len, const void* dst, std::size_t dst_len) {
    // Handle edge cases: null pointers or zero-length regions
    if (!src || !dst || src_len == 0 || dst_len == 0) {
        return false;
    }

    // Convert pointers to unsigned integers for safe comparison
    uintptr_t src_start = uintptr_from_ptr(src);
    uintptr_t src_end = src_start + src_len;
    uintptr_t dst_start = uintptr_from_ptr(dst);
    uintptr_t dst_end = dst_start + dst_len;

    // Two regions overlap if neither ends before the other starts
    // They DON'T overlap if: src_end <= dst_start OR dst_end <= src_start
    // So they DO overlap if the negation is true
    return !(src_end <= dst_start || dst_end <= src_start);
}

bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    // Check for null pointers
    if (!destination || !source) {
        return false;
    }

    // Check for overlap between source and destination regions
    if (check_regions_overlap(source, length, destination, length)) {
        return false; // Overlap detected, memcpy is not safe
    }

    // No overlap detected, safe to perform copy
    std::memcpy(destination, source, length);
    return true;
}
```

