```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct CompactPacket {
    uint32_t packet_id;
    std::vector<std::string> tags;
    std::string data;
};

std::vector<uint8_t> serialize_compact_packet(const CompactPacket& packet) {
    // Create a buffer writer for serialization
    hexi::buffer_writer writer;

    // Write packet_id as varint for compact encoding
    writer.write_varint(packet.packet_id);

    // Write tags vector with prefixed_varint adaptor
    // This encodes the vector size as varint, then each string with varint length prefix
    writer.write(hexi::prefixed_varint(packet.tags));

    // Write data string with prefixed_varint adaptor
    // This encodes the string length as varint, then the string content
    writer.write(hexi::prefixed_varint(packet.data));

    // Return the serialized binary data
    return writer.data();
}

CompactPacket deserialize_compact_packet(const std::span<const uint8_t> buffer) {
    // Create a buffer reader for deserialization
    hexi::buffer_reader reader(buffer);

    CompactPacket packet;

    // Read packet_id as varint
    packet.packet_id = reader.read_varint<uint32_t>();

    // Read tags vector with prefixed_varint adaptor
    // This reads the varint size prefix, then deserializes each string element
    reader.read(hexi::prefixed_varint(packet.tags));

    // Read data string with prefixed_varint adaptor
    // This reads the varint length prefix, then the string content
    reader.read(hexi::prefixed_varint(packet.data));

    return packet;
}
```

## Key Points:

1. **`hexi::buffer_writer`**: Used to serialize data to a binary buffer
2. **`hexi::buffer_reader`**: Used to deserialize data from a binary buffer
3. **`write_varint()`**: Writes an integer using variable-length encoding (smaller values use fewer bytes)
4. **`read_varint<T>()`**: Reads a varint-encoded integer
5. **`hexi::prefixed_varint()`**: Adaptor that automatically encodes/decodes the size of containers and strings as varints, making the serialization compact
6. **For vectors of strings**: The `prefixed_varint` adaptor encodes both the vector size and each individual string's length as varints
7. **Efficiency**: Small values use 1 byte, medium values use 2-3 bytes, large values use more bytes as needed

